#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""ATLAS single-authority live metrics (the 409-proof observability fix). ONE process,
ONE committer of status/hetzner/metrics-live.json -> no write race. Measures GROSS
enrichment throughput via a timestamp-column delta (immune to re-queue churn) + net drain
+ connections + per-pool worker liveness. 30s cadence, bounded queries, strong 409 retry."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error,random
STATE="/var/lib/atlas/metrics-live-state.json"
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#') and '=' in ln:
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
ENV={}; ENV.update(envf("/etc/atlas/db.env")); ENV.update(envf("/etc/atlas/autopull.env"))
TOK=ENV.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN")
REPO=ENV.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
def psql(q,t=12):
    try:
        r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc","SET statement_timeout='9s'; "+q],capture_output=True,text=True,timeout=t)
        return r.stdout.strip() if r.returncode==0 and r.stdout.strip() else None
    except Exception: return None
def sh(c,t=8):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return r.stdout.strip()
    except Exception: return None
def find_ts_col():
    cols=psql("SELECT string_agg(column_name,',') FROM information_schema.columns WHERE table_schema='atlas' AND table_name='enrich_queue'")
    if not cols: return None
    s=set(cols.split(','))
    for c in ['done_at','updated_at','enriched_at','finished_at','completed_at','claimed_at','last_attempt','ts']:
        if c in s: return c
    return None
def gh_put(path,obj):
    if not TOK: return "no-token"
    url="https://api.github.com/repos/%s/contents/%s"%(REPO,path); sha=None
    try:
        rq=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+TOK,"Accept":"application/vnd.github+json","User-Agent":"atlas-metrics"}); sha=json.load(urllib.request.urlopen(rq,timeout=15)).get("sha")
    except Exception: sha=None
    body={"message":"metrics-live","content":base64.b64encode(json.dumps(obj,indent=1,default=str).encode()).decode(),"branch":"main"}
    if sha: body["sha"]=sha
    for i in range(10):
        try:
            rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+TOK,"Accept":"application/vnd.github+json","User-Agent":"atlas-metrics","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=20); return "ok"
        except urllib.error.HTTPError as e:
            if e.code==409:
                time.sleep(0.3+random.random()*1.2)
                try:
                    rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+TOK,"Accept":"application/vnd.github+json","User-Agent":"atlas-metrics"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=15)).get("sha")
                except Exception: pass
            else: return "http_%s"%e.code
        except Exception: time.sleep(1)
    return "exhausted"
def main():
    os.makedirs("/var/lib/atlas",exist_ok=True)
    TS=find_ts_col()
    while True:
        m={"kind":"metrics-live","ts":int(time.time()),"ts_col":TS}
        m["pg_conns"]=psql("SELECT count(*) FROM pg_stat_activity")
        m["pg_active"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
        m["max_conns"]=psql("SELECT current_setting('max_connections')")
        qd=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue")
        m["queue_done"]=qd
        m["queue_pending"]=psql("SELECT count(*) FILTER (WHERE status='pending') FROM atlas.enrich_queue")
        if TS:
            m["enrich_per_min_gross"]=psql("SELECT count(*) FROM atlas.enrich_queue WHERE %s > now()-interval '60 seconds'"%TS)
        m["enrich_pool_active"]=sh("systemctl list-units 'atlas-enrich-pool@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
        m["crawler_pool_active"]=sh("systemctl list-units 'atlas-deepcrawl-pool@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
        m["async_active"]=sh("systemctl is-active atlas-enrich-async@1.service 2>/dev/null") or ""
        try:
            prev=json.load(open(STATE)); dt=m["ts"]-prev.get("ts",0)
            if dt>0 and qd and prev.get("queue_done"):
                m["net_drain_per_min"]=round((int(qd)-int(prev["queue_done"]))*60.0/dt,1)
        except Exception: pass
        try: json.dump({"ts":m["ts"],"queue_done":qd},open(STATE,"w"))
        except Exception: pass
        m["publish"]=gh_put("status/hetzner/metrics-live.json",m)
        time.sleep(30)
if __name__=="__main__":
    try: main()
    except Exception as e:
        try: gh_put("status/hetzner/metrics-live.json",{"kind":"metrics-live","fatal":str(e),"ts":int(time.time())})
        except Exception: pass
        sys.exit(0)
